    const ICONS = { 'Healthcare': '🏥', 'Technology': '💻', 'Technology & SaaS': '💻', 'Real Estate': '🏠', 'Tourism & Hospitality': '🏨', 'Tourism': '🏨', 'Agriculture': '🌾', 'Agriculture & Food': '🌾', 'Manufacturing': '🏭', 'Financial Services': '🏦', 'Law Firms': '⚖️', 'eCommerce': '🛒', 'Retail & eCommerce': '🛒', 'Construction': '🏗️', 'Oil & Gas': '⛽', 'Oil & Energy': '⛽', 'Energy': '⚡', 'Restaurants': '🍕', 'Education': '📚', 'Biotech & Pharma': '🧬', 'Automotive & Mobility': '🚗', 'Logistics': '🚚', 'Retail': '🛍️', 'Entertainment & Media': '🎬', 'Outdoor & Recreation': '🏔️', 'Outdoor Recreation': '🏔️', 'Aerospace & Defense': '✈️', 'Government & Defense Contracting': '🏛️', 'Insurance': '📋', 'Music & Entertainment': '🎵', 'Pharmaceutical & Life Sciences': '🧬', 'Fishing & Seafood': '🐟', 'Food & Agriculture': '🌽', 'Higher Education': '🎓', 'Advanced Manufacturing': '🏭' };
